import { IEventRepository } from '../../domain/repositories/IEventRepository';
import { Event } from '../../domain/entities/Event';
import { inMemoryDatabase } from '../database/inMemoryDatabase';

export class EventRepository implements IEventRepository {
  async findAll(): Promise<Event[]> {
    return inMemoryDatabase.events.findAll();
  }

  async findById(id: string): Promise<Event | null> {
    const event = await inMemoryDatabase.events.findById(id);
    return event || null;
  }

  async findBySource(source: string): Promise<Event[]> {
    return inMemoryDatabase.events.findBySource(source);
  }

  async create(event: Omit<Event, 'id' | 'createdAt' | 'updatedAt'>): Promise<Event> {
    return inMemoryDatabase.events.create(event);
  }

  async update(id: string, event: Partial<Omit<Event, 'id' | 'createdAt' | 'updatedAt'>>): Promise<Event | null> {
    const updated = await inMemoryDatabase.events.update(id, event);
    return updated || null;
  }

  async delete(id: string): Promise<boolean> {
    return inMemoryDatabase.events.delete(id);
  }
}

export type RetryOptions = {
  retries?: number;
  delayMs?: number;
  backoffFactor?: number;
  shouldRetry?: (error: unknown, attempt: number) => boolean;
};

export async function withRetry<T>(
  fn: () => Promise<T>,
  {
    retries = 3,
    delayMs = 500,
    backoffFactor = 2,
    shouldRetry = () => true,
  }: RetryOptions = {},
): Promise<T> {
  if (retries <= 0) {
    throw new Error("retries must be >= 1");
  }

  let attempt = 0;
  let lastError: unknown;

  while (attempt < retries) {
    try {
      return await fn();
    } catch (err) {
      lastError = err;
      attempt++;

      if (attempt >= retries || !shouldRetry(err, attempt)) {
        throw err;
      }

      const delay = delayMs * Math.pow(backoffFactor, attempt - 1);

      await new Promise((r) => setTimeout(r, delay));
    }
  }

  throw lastError;
}

